public async getSigner(
  address?: number | string,
): Promise<HardhatEthersSigner> {
  if (address === null || address === undefined) {
    address = 0;
  }

  const accountsPromise = this.send("eth_accounts", []);

  // Account index
  if (typeof address === "number") {
    const accounts: string[] = await accountsPromise;
    if (address >= accounts.length) {
      throw new HardhatError(
        HardhatError.ERRORS.HARDHAT_ETHERS.GENERAL.ACCOUNT_INDEX_OUT_OF_RANGE,
        {
          accountIndex: address,
          accountsLength: accounts.length,
        },
      );
    }
    return await HardhatEthersSigner.create(
      this,
      this.#networkName,
      this.#networkConfig,
      accounts[address],
    );
  }

  if (typeof address === "string") {
    return await HardhatEthersSigner.create(
      this,
      this.#networkName,
      this.#networkConfig,
      address,
    );
  }

  throw new HardhatError(
    HardhatError.ERRORS.HARDHAT_ETHERS.GENERAL.CANNOT_GET_ACCOUNT,
    {
      address,
    },
  );
}

public async getFeeData(): Promise<ethers.FeeData> {
  let gasPrice: bigint | undefined;
  let maxFeePerGas: bigint | undefined;
  let maxPriorityFeePerGas: bigint | undefined;

  try {
    const value = await this.#hardhatProvider.request({
      method: "eth_gasPrice",
    });

    assertCanConvertToBigInt(value, "value");

    gasPrice = BigInt(value);
  } catch {}

  const latestBlock = await this.getBlock("latest");
  const baseFeePerGas = latestBlock?.baseFeePerGas;
  if (baseFeePerGas !== undefined && baseFeePerGas !== null) {
    try {
      const value = await this.#hardhatProvider.request({
        method: "eth_maxPriorityFeePerGas",
      });

      assertCanConvertToBigInt(value, "value");

      maxPriorityFeePerGas = BigInt(value);
    } catch {
      // the max priority fee RPC call is not supported by
      // this chain
    }

    maxPriorityFeePerGas = maxPriorityFeePerGas ?? 1_000_000_000n;
    maxFeePerGas = 2n * baseFeePerGas + maxPriorityFeePerGas;
  }

  return new FeeData(gasPrice, maxFeePerGas, maxPriorityFeePerGas);
}

function decodeError(
  returnData: string,
  customErrorReported: boolean,
  decodeCustomError?: (
    returnData: string
  ) => RevertWithCustomError | RevertWithInvalidData | undefined
): FailedEvmExecutionResult {
  if (returnData === "0x") {
    return { type: EvmExecutionResultTypes.REVERT_WITHOUT_REASON };
  }

  const revertWithReasonError = tryToDecodeReason(returnData);
  if (revertWithReasonError !== undefined) {
    return revertWithReasonError;
  }

  const revertWithPanicCodeError = tryToDecodePanicCode(returnData);
  if (revertWithPanicCodeError !== undefined) {
    return revertWithPanicCodeError;
  }

  if (decodeCustomError !== undefined) {
    const decodedCustomError = decodeCustomError(returnData);
    if (decodedCustomError !== undefined) {
      return decodedCustomError;
    }
  }

  if (customErrorReported === true) {
    return {
      type: EvmExecutionResultTypes.REVERT_WITH_UNKNOWN_CUSTOM_ERROR,
      signature: returnData.slice(0, 10),
      data: returnData,
    };
  }

  return {
    type: EvmExecutionResultTypes.REVERT_WITH_INVALID_DATA_OR_UNKNOWN_CUSTOM_ERROR,
    signature: returnData.slice(0, 10),
    data: returnData,
  };
}

public async getLatestBlock(): Promise<Block> {
  const response = await this._provider.request({
    method: "eth_getBlockByNumber",
    params: ["latest", false],
  });

  assertResponseType(
    "eth_getBlockByNumber",
    response,
    typeof response === "object" && response !== null
  );

  assertResponseType(
    "eth_getBlockByNumber",
    response,
    "number" in response && typeof response.number === "string"
  );

  assertResponseType(
    "eth_getBlockByNumber",
    response,
    "hash" in response && typeof response.hash === "string"
  );

  let baseFeePerGas: bigint | undefined;
  if ("baseFeePerGas" in response) {
    assertResponseType(
      "eth_getBlockByNumber",
      response,
      typeof response.baseFeePerGas === "string"
    );

    baseFeePerGas = jsonRpcQuantityToBigInt(response.baseFeePerGas);
  }

  return {
    number: jsonRpcQuantityToNumber(response.number),
    hash: response.hash,
    baseFeePerGas,
  };
}

public async wipe(futureId: string) {
  const deploymentState = await loadDeploymentState(this._deploymentLoader);

  if (deploymentState === undefined) {
    throw new IgnitionError(ERRORS.WIPE.UNINITIALIZED_DEPLOYMENT, {
      futureId,
    });
  }

  const executionState = deploymentState.executionStates[futureId];

  if (executionState === undefined) {
    throw new IgnitionError(ERRORS.WIPE.NO_STATE_FOR_FUTURE, { futureId });
  }

  const dependents = Object.values(deploymentState.executionStates).filter(
    (psm) => psm.dependencies.has(futureId)
  );

  if (dependents.length > 0) {
    throw new IgnitionError(ERRORS.WIPE.DEPENDENT_FUTURES, {
      futureId,
      dependents: dependents.map((d) => d.id).join(", "),
    });
  }

  const wipeMessage: WipeExecutionStateMessage = {
    type: JournalMessageType.WIPE_APPLY,
    futureId,
  };

  return applyNewMessage(
    wipeMessage,
    deploymentState,
    this._deploymentLoader
  );
}

function resolveStrategy<StrategyT extends keyof StrategyConfig>(
  strategyName: StrategyT | undefined,
  strategyConfig: StrategyConfig[StrategyT] | undefined
): ExecutionStrategy {
  if (strategyName === undefined) {
    return new BasicStrategy();
  }

  switch (strategyName) {
    case "basic":
      return new BasicStrategy();
    case "create2":
      if (strategyConfig === undefined) {
        throw new IgnitionError(ERRORS.STRATEGIES.MISSING_CONFIG, {
          strategyName,
        });
      }

      if (typeof strategyConfig.salt !== "string") {
        throw new IgnitionError(ERRORS.STRATEGIES.MISSING_CONFIG_PARAM, {
          strategyName,
          requiredParam: "salt",
        });
      }

      if (hexStringLengthInBytes(strategyConfig.salt) !== 32) {
        throw new IgnitionError(ERRORS.STRATEGIES.INVALID_CONFIG_PARAM, {
          strategyName,
          paramName: "salt",
          reason: "The salt must be 32 bytes in length",
        });
      }

      return new Create2Strategy({ salt: strategyConfig.salt });
    default:
      throw new IgnitionError(ERRORS.STRATEGIES.UNKNOWN_STRATEGY, {
        strategyName,
      });
  }
}

public async execute() {
  const currentHardhatDir = await ensureCurrentHardhatDir(this.state);

  if (currentHardhatDir === undefined) {
    return;
  }

  if (!(await ensureHardhatIsInstalled(currentHardhatDir))) {
    return;
  }

  if (!(await this.beforeExecute())) return;

  const cliPath = getHardhatCLIPath(currentHardhatDir);

  this.state.outputChannel.appendLine(
    `Running 'hardhat ${this.hardhatArgs().join(" ")}'\n`
  );

  const exitStatus = await withProgressNotification(
    this.progressLabel(),
    async () => {
      return new Promise((resolve) => {
        const childProcess = spawn("node", [cliPath, ...this.hardhatArgs()], {
          cwd: currentHardhatDir,
        });

        childProcess.stdout.on("data", (data) => {
          this.onStdout(data.toString());
        });

        childProcess.stderr.on("data", (data) => {
          this.onStderr(data.toString());
        });

        childProcess.on("close", async (_status: number) => {
          this.onClose(_status);
          resolve(_status);
        });
      });
    }
  );

  if (exitStatus !== 0) {
    this.state.outputChannel.show();
    await vscode.window.showErrorMessage(
      "Solidity command errored, please see output logs."
    );
  }
}

public async listeners(
  ethersEvent?: ProviderEvent | undefined,
): Promise<Listener[]> {
  if (ethersEvent === undefined) {
    throw new HardhatError(
      HardhatError.ERRORS.HARDHAT_ETHERS.GENERAL.METHOD_NOT_IMPLEMENTED,
      {
        method: "listeners()",
      },
    );
  }

  const event = ethersToHardhatEvent(ethersEvent);

  if (event.kind === "block") {
    return this.#blockListeners.map(({ listener }) => listener);
  } else if (event.kind === "transactionHash") {
    return (
      this.#transactionHashListeners
        .get(event.txHash)
        ?.map(({ listener }) => listener) ?? []
    );
  } else if (event.kind === "event") {
    const eventListener = await this.#findEventListener(event.eventFilter);

    if (eventListener === undefined) {
      return [];
    }

    return [...eventListener.listenersMap.keys()];
  } else {
    const _exhaustiveCheck: never = event;
    return _exhaustiveCheck;
  }
}

#getBlockTag(blockTag?: BlockTag): string | Promise<string> {
  if (blockTag === null || blockTag === undefined) {
    return "latest";
  }

  switch (blockTag) {
    case "earliest":
      return "0x0";
    case "latest":
    case "pending":
    case "safe":
    case "finalized":
      return blockTag;
    default:
  }

  if (isHexString(blockTag)) {
    if (isHexString(blockTag, 32)) {
      return blockTag;
    }
    return toQuantity(blockTag);
  }

  if (typeof blockTag === "number") {
    if (blockTag >= 0) {
      return toQuantity(blockTag);
    }
    return this.getBlockNumber().then((b) => toQuantity(b + blockTag));
  }

  if (typeof blockTag === "bigint") {
    if (blockTag >= 0n) {
      return toQuantity(blockTag);
    }
    return this.getBlockNumber().then((b) =>
      toQuantity(b + Number(blockTag)),
    );
  }

  throw new HardhatError(
    HardhatError.ERRORS.HARDHAT_ETHERS.GENERAL.INVALID_BLOCK_TAG,
    {
      blockTag,
    },
  );
}

private resolveConstructorPredicate(): (abiEntry: starknet.AbiEntry) => boolean {
    if (!this.isCairo1()) {
        return (abiEntry: starknet.AbiEntry): boolean => {
            return abiEntry.type === "constructor";
        };
    }

    const casmJson = JSON.parse(fs.readFileSync(this.casmPath, "utf-8"));
    if (casmJson?.compiler_version.split(".")[0] === "0") {
        const msg = ".CASM json should have been generated with a compiler version >= 1";
        throw new StarknetPluginError(msg);
    }

    const constructors = casmJson?.entry_points_by_type?.CONSTRUCTOR;
    if (!constructors || constructors.length === 0) {
        return () => false;
    }

    // Can be removed after new cairo release.
    if (constructors.length > 1) {
        const msg = "There can be at most 1 constructor.";
        throw new StarknetPluginError(msg);
    }

    // Can be simplified once starkware fixes multiple constructor issue.
    // Precomputed selector can be used if only 'constructor' name allowed
    const constructorSelector = constructors[0].selector;
    return (abiEntry: starknet.AbiEntry): boolean => {
        return selector.getSelectorFromName(abiEntry.name) === constructorSelector;
    };
}

protected _invalidateCacheMissingArtifacts(
  circuitSetupInfoArr: CircuitSetupInfo[],
  provingSystems: ProvingSystemType[],
) {
  for (const setupInfo of circuitSetupInfoArr) {
    const cacheEntry = CircuitsSetupCache!.getEntry(setupInfo.circuitArtifactFullPath);

    if (cacheEntry === undefined) {
      continue;
    }

    const provingSystemsToRemove: ProvingSystemType[] = [];

    for (const provingSystem of provingSystems) {
      if (
        !fsExtra.existsSync(
          this._circuitArtifacts.getCircuitArtifactFileFullPath(setupInfo.circuitArtifact, "zkey", provingSystem),
        ) ||
        !fsExtra.existsSync(
          this._circuitArtifacts.getCircuitArtifactFileFullPath(setupInfo.circuitArtifact, "vkey", provingSystem),
        )
      ) {
        provingSystemsToRemove.push(provingSystem);
      }
    }

    cacheEntry.provingSystemsData = cacheEntry.provingSystemsData.filter(
      (data) => !provingSystemsToRemove.includes(data.provingSystem),
    );

    if (cacheEntry.provingSystemsData.length > 0) {
      CircuitsSetupCache!.addFile(setupInfo.circuitArtifactFullPath, cacheEntry);
    } else {
      CircuitsSetupCache!.removeEntry(setupInfo.circuitArtifactFullPath);
    }
  }
}

public hasFileChanged(
  artifactAbsolutePath: string,
  r1csContentHash: string,
  contributionSettings: SetupContributionSettings,
): ProvingSystemType[] {
  const cacheEntry = this.getEntry(artifactAbsolutePath);

  if (cacheEntry === undefined) {
    return contributionSettings.provingSystems;
  }

  const obsoleteProvingSystems: ProvingSystemType[] = [];

  for (const provingSystem of contributionSettings.provingSystems) {
    const provingSystemData: ProvingSystemData | undefined = cacheEntry.provingSystemsData.find(
      (data: ProvingSystemData) => data.provingSystem === provingSystem,
    );

    if (!provingSystemData) {
      obsoleteProvingSystems.push(provingSystem);

      continue;
    }

    if (
      provingSystemData.lastR1CSFileHash !== r1csContentHash ||
      (provingSystem === "groth16" && cacheEntry.contributionsNumber !== contributionSettings.contributions)
    ) {
      obsoleteProvingSystems.push(provingSystem);
    }
  }

  return obsoleteProvingSystems;
}

private _getBatchSortedByHighesPendingNonce(
  batch: Future[],
  deploymentState: DeploymentState
): Future[] {
  const batchWithNonces = batch.map((f) => {
    const NO_PENDING_RESULT = {
      future: f,
      nonce: Number.MAX_SAFE_INTEGER,
      from: "0xFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFF",
    };

    const exState = deploymentState.executionStates[f.id];

    if (exState === undefined) {
      return NO_PENDING_RESULT;
    }

    const pendingNonceAndSender = getPendingNonceAndSender(exState);

    if (pendingNonceAndSender === undefined) {
      return NO_PENDING_RESULT;
    }

    return {
      future: f,
      nonce: pendingNonceAndSender.nonce,
      from: pendingNonceAndSender.sender,
    };
  });

  const sortBy = require("lodash/sortBy") as typeof import("lodash/sortBy");
  const sortedBatch = sortBy(batchWithNonces, ["from", "nonce", "future.id"]);

  return sortedBatch.map((f) => f.future);
}

async function analyzeSolFile(
  { solFileIndex }: { solFileIndex: SolFileIndexMap },
  solFileEntry: ISolFileEntry,
  newText?: string
): Promise<Node | undefined> {
  try {
    solFileEntry.orphanNodes = [];

    if (newText !== undefined) {
      solFileEntry.text = newText;
    }

    try {
      solFileEntry.ast = parser.parse(solFileEntry.text ?? "", {
        loc: true,
        range: true,
        tolerant: true,
      });
    } catch {
      solFileEntry.status = SolFileState.ERRORED;
      return solFileEntry.analyzerTree.tree;
    }

    if (solFileEntry.isAnalyzed()) {
      const oldDocumentsAnalyzerTree = solFileEntry.analyzerTree
        .tree as SourceUnitNode;

      for (const importNode of oldDocumentsAnalyzerTree.getImportNodes()) {
        importNode.getParent()?.removeChild(importNode);
        importNode.setParent(undefined);
      }
    }

    solFileEntry.status = SolFileState.ANALYZED;
    const node = await matcher.find(
      solFileEntry.ast,
      solFileEntry.uri,
      solFileEntry.project.basePath,
      solFileIndex
    );
    solFileEntry.analyzerTree.tree = await node.accept(
      matcher.find,
      solFileEntry.orphanNodes
    );

    return solFileEntry.analyzerTree.tree;
  } catch {
    return solFileEntry.analyzerTree.tree;
  }
}

async function forgeFormat(
  text: string,
  document: TextDocument,
  logger: Logger
) {
  const forgeCommand = await resolveForgeCommand();
  const documentPath = URI.parse(document.uri).fsPath;
  const cwd = path.dirname(documentPath);

  logger.trace(`Forge command: ${forgeCommand}`);
  logger.trace(`CWD: ${cwd}`);

  // Wait for the formatted output
  try {
    const { stdout: formattedText } = await execWithInput(
      `${forgeCommand} fmt --raw -`,
      text,
      {
        cwd,
        timeout: FORMAT_TIMEOUT,
      }
    );

    // Build and return a text edit with the entire file content
    const textEdit: TextEdit = {
      range: {
        start: { line: 0, character: 0 },
        end: document.positionAt(text.length),
      },
      newText: formattedText,
    };

    return [textEdit];
  } catch (error: unknown) {
    if (isKilledDefinedExecException(error) && error.killed === true) {
      throw new TimeoutError(FORMAT_TIMEOUT);
    } else {
      throw error;
    }
  }
}

function calculateDeploymentCompleteDisplay(
  uiState: Pick<
    UiState,
    "moduleName" | "isResumed" | "batches" | "deploymentDir" | "result"
  >,
): string {
  const moduleName = uiState.moduleName ?? "unknown";
  const isResumed = uiState.isResumed ?? false;

  // type inference
  assertHardhatInvariant(uiState.result !== null, "Result is null");

  switch (uiState.result.type) {
    case DeploymentResultType.SUCCESSFUL_DEPLOYMENT: {
      const isRerunWithNoChanges: boolean =
        isResumed && !wasAnythingExecuted(uiState);

      return _displaySuccessfulDeployment(uiState.result, {
        moduleName,
        isRerunWithNoChanges,
        deploymentDir: uiState.deploymentDir,
      });
    }
    case DeploymentResultType.VALIDATION_ERROR: {
      return _displayValidationErrors(uiState.result, { moduleName });
    }
    case DeploymentResultType.RECONCILIATION_ERROR: {
      return _displayReconciliationErrors(uiState.result, { moduleName });
    }
    case DeploymentResultType.PREVIOUS_RUN_ERROR: {
      return _displayPreviousRunErrors(uiState.result, { moduleName });
    }
    case DeploymentResultType.EXECUTION_ERROR: {
      return _displayExecutionErrors(uiState.result, { moduleName });
    }
  }
}

private async _prepareTransaction(transaction: TransactionRequest): Promise<TransactionLike> {
    const tx = await this.populateFeeData(transaction);

    if (tx.type === null || tx.type === undefined || tx.type === EIP712_TX_TYPE || tx.customData) {
        const address = await this.getAddress();
        tx.from ??= address;
        if (!isAddressEq(await ethers.resolveAddress(tx.from), address)) {
            throw new Error('Transaction `from` address mismatch!');
        }
        const zkTx: TransactionLike = {
            type: tx.type ?? EIP712_TX_TYPE,
            value: tx.value ?? 0,
            data: tx.data ?? '0x',
            nonce: tx.nonce ?? (await this.getNonce()),
            maxFeePerGas: tx.gasPrice ?? tx.maxFeePerGas,
            maxPriorityFeePerGas: tx.maxPriorityFeePerGas,
            gasLimit: tx.gasLimit,
            chainId: tx.chainId ?? (await this.provider.getNetwork()).chainId,
            to: await ethers.resolveAddress(tx.to!),
            customData: this._fillCustomData(tx.customData ?? {}),
            from: address,
        };
        zkTx.customData ??= {};

        return zkTx;
    }

    return await super.populateTransaction(tx);
}

function validateTasksConfig(
  tasks: TaskDefinition[],
  path: Array<string | number> = [],
  isPlugin: boolean = false,
): HardhatUserConfigValidationError[] {
  const validationErrors: HardhatUserConfigValidationError[] = [];

  for (const [index, task] of tasks.entries()) {
    if (!isTaskDefinition(task)) {
      validationErrors.push({
        path: [...path, "tasks", index],
        message: "tasks must be an array of TaskDefinitions",
      });

      continue;
    }

    switch (task.type) {
      case TaskDefinitionType.EMPTY_TASK: {
        validationErrors.push(
          ...validateEmptyTask(task, [...path, "tasks", index]),
        );
        break;
      }
      case TaskDefinitionType.NEW_TASK: {
        validationErrors.push(
          ...validateNewTask(task, [...path, "tasks", index], isPlugin),
        );
        break;
      }
      case TaskDefinitionType.TASK_OVERRIDE: {
        validationErrors.push(
          ...validateTaskOverride(task, [...path, "tasks", index], isPlugin),
        );
        break;
      }
    }
  }

  return validationErrors;
}

public getTask(taskId: string | string[]): Task {
  taskId = Array.isArray(taskId) ? taskId : [taskId];
  if (taskId.length === 0) {
    throw new HardhatError(
      HardhatError.ERRORS.CORE.TASK_DEFINITIONS.TASK_NOT_FOUND,
      {
        task: formatTaskId(taskId),
      },
    );
  }

  let tasks = this.#rootTasks;
  let task: Task | undefined;
  for (let i = 0; i < taskId.length; i++) {
    const idFragment = taskId[i];
    const currentTask = tasks.get(idFragment);
    if (currentTask === undefined) {
      throw new HardhatError(
        HardhatError.ERRORS.CORE.TASK_DEFINITIONS.TASK_NOT_FOUND,
        {
          task: formatTaskId(taskId.slice(0, i + 1)),
        },
      );
    }

    task = currentTask;
    tasks = task.subtasks;
  }

  assertHardhatInvariant(
    task !== undefined,
    "Task is undefined despite it being always set by a non-empty loop",
  );

  return task;
}

async function sendDeployAccountTx(
    signatures: string[],
    classHash: string,
    constructorCalldata: string[],
    salt: string,
    maxFee: string
) {
    const hre = await import("hardhat");
    const resp = await axios
        .post(`${hre.starknet.networkConfig.url}/gateway/add_transaction`, {
            max_fee: maxFee,
            signature: signatures,
            nonce: INITIAL_NONCE,
            class_hash: classHash,
            contract_address_salt: salt,
            constructor_calldata: constructorCalldata,
            version: numericToHexString(TRANSACTION_VERSION),
            type: "DEPLOY_ACCOUNT"
        })
        .catch((error: AxiosError<starknet.StarkError>) => {
            const msg = `Deploying account failed: ${error.response.data.message}`;
            throw new StarknetPluginError(msg, error);
        });

    return new Promise<string>((resolve, reject) => {
        iterativelyCheckStatus(
            resp.data.transaction_hash,
            hre.starknetWrapper,
            () => resolve(resp.data.transaction_hash),
            reject
        );
    });
}

function shortStringToBigIntUtil(convertibleString: string) {
    if (!convertibleString) {
        throw new StarknetPluginError("A non-empty string must be provided");
    }

    if (convertibleString.length > SHORT_STRING_MAX_CHARACTERS) {
        const msg = `Short strings must have a max of ${SHORT_STRING_MAX_CHARACTERS} characters.`;
        throw new StarknetPluginError(msg);
    }

    const invalidChars: { [key: string]: boolean } = {};
    const charArray = [];
    for (const c of convertibleString.split("")) {
        const charCode = c.charCodeAt(0);
        if (charCode > 127) {
            invalidChars[c] = true;
        }
        charArray.push(charCode.toString(16));
    }

    const invalidCharArray = Object.keys(invalidChars);
    if (invalidCharArray.length) {
        const msg = `Non-standard-ASCII character${
            invalidCharArray.length === 1 ? "" : "s"
        }: ${invalidCharArray.join(", ")}`;
        throw new StarknetPluginError(msg);
    }

    return BigInt("0x" + charArray.join(""));
}

public async setup(circuitSetupInfoArr: CircuitSetupInfo[], contributionSettings: SetupContributionSettings) {
  const tempDir: string = path.join(os.tmpdir(), ".zkit", uuid());

  try {
    fsExtra.mkdirSync(tempDir, { recursive: true });

    Reporter!.reportSetupProcessHeader();

    const ptauFilePath: string = await this._getPtauFile(circuitSetupInfoArr, contributionSettings.provingSystems);

    await this._generateZKeyFiles(circuitSetupInfoArr, contributionSettings, ptauFilePath);
    await this._generateVKeyFiles(circuitSetupInfoArr);

    await Promise.all(
      circuitSetupInfoArr.map(async (setupInfo: CircuitSetupInfo) => {
        await this._circuitArtifacts.saveCircuitArtifact(
          setupInfo.circuitArtifact,
          ["zkey", "vkey"],
          setupInfo.provingSystems,
        );
      }),
    );

    Reporter!.reportSetupResult(circuitSetupInfoArr);
  } finally {
    fsExtra.rmSync(tempDir, { recursive: true, force: true });
  }
}

function updateCache(setupContributionSettings: SetupContributionSettings, circuitSetupInfoArr: CircuitSetupInfo[]) {
  for (const setupInfo of circuitSetupInfoArr) {
    const currentSetupCacheEntry = CircuitsSetupCache!.getEntry(setupInfo.circuitArtifactFullPath);

    let currentProvingSystemsData: ProvingSystemData[] = [];

    if (currentSetupCacheEntry) {
      // Getting untouched proving systems data
      currentProvingSystemsData = currentSetupCacheEntry.provingSystemsData.filter((data: ProvingSystemData) => {
        return !setupInfo.provingSystems.includes(data.provingSystem);
      });
    }

    CircuitsSetupCache!.addFile(setupInfo.circuitArtifactFullPath, {
      circuitSourceName: setupInfo.circuitArtifact.circuitSourceName,
      r1csSourcePath: setupInfo.r1csSourcePath,
      provingSystemsData: [
        ...currentProvingSystemsData,
        ...setupContributionSettings.provingSystems.map((provingSystem) => {
          return {
            provingSystem,
            lastR1CSFileHash: setupInfo.r1csContentHash,
          };
        }),
      ],
      contributionsNumber: setupContributionSettings.contributions,
    });
  }
}

public update(
    _compiler: SolcConfig,
    _latestEraVersion: string,
    _zksolc: ZkSolcConfig,
    _userConfigCompilers: SolcUserConfig[],
    _file?: string,
): void {
    const compilerInfos = _userConfigCompilers.filter(
        (userCompilerInfo) => userCompilerInfo.version === _compiler.version,
    );

    if (compilerInfos.length > 1) {
        const compilerInfosWithEraVersion = compilerInfos.filter((userCompilerInfo) => userCompilerInfo.eraVersion);

        if (compilerInfosWithEraVersion.length > 0 && compilerInfosWithEraVersion.length !== compilerInfos.length) {
            throw new ZkSyncSolcPluginError(COMPILERS_CONFLICT_ZKVM_SOLC(_compiler.version));
        }
    }

    const compilerInfo = compilerInfos[0];

    if (compilerInfo?.eraVersion) {
        _compiler.eraVersion = compilerInfo.eraVersion;
        return;
    }

    if (isBreakableCompilerVersion(_zksolc.version)) {
        _compiler.eraVersion = _latestEraVersion;
    }
}

public normalize(
    _compiler: SolcConfig,
    _zkSolcConfig: any,
    _latestEraVersion: string,
    _userConfigCompilers: SolcUserConfig[],
    _file?: string,
): string {
    const compilerInfos = _userConfigCompilers.filter(
        (userCompilerInfo) => userCompilerInfo.version === _compiler.version,
    );

    if (compilerInfos.length > 1) {
        const compilerInfosWithEraVersion = compilerInfos.filter((userCompilerInfo) => userCompilerInfo.eraVersion);

        if (compilerInfosWithEraVersion.length > 0 && compilerInfosWithEraVersion.length !== compilerInfos.length) {
            throw new ZkSyncVerifyPluginError(COMPILERS_CONFLICT_ZKVM_SOLC(_compiler.version));
        }
    }

    const compilerInfo = compilerInfos[0];

    if (isBreakableCompilerVersion(_zkSolcConfig.version)) {
        return compilerInfo?.eraVersion
            ? getZkVmNormalizedVersion(_compiler.version, compilerInfo.eraVersion)
            : getZkVmNormalizedVersion(_compiler.version, _latestEraVersion);
    }

    return compilerInfo?.eraVersion
        ? getZkVmNormalizedVersion(_compiler.version, compilerInfo.eraVersion)
        : _compiler.version;
}

async function getWalletsFromAccount(
    hre: HardhatRuntimeEnvironment,
    accounts: HardhatNetworkAccountsConfig | HttpNetworkAccountsConfig,
): Promise<Wallet[]> {
    if (!accounts || accounts === 'remote') {
        return await getRichWalletsIfPossible(hre);
    }

    if (isHardhatNetworkAccountsConfigStrings(accounts)) {
        const accountPrivateKeys = accounts as string[];

        const wallets = accountPrivateKeys.map((accountPrivateKey) =>
            new Wallet(accountPrivateKey, hre.ethers.provider).connectToL1(hre.ethers.providerL1),
        );
        return wallets;
    }

    if (isHardhatNetworkHDAccountsConfig(accounts)) {
        const account = accounts as HardhatNetworkHDAccountsConfig;

        const wallet = Wallet.fromMnemonic(account.mnemonic)
            .connect(hre.ethers.provider)
            .connectToL1(hre.ethers.providerL1);
        return [wallet];
    }

    return [];
}

function determineIsFunctionHeaderOnSameLine(
  functionToken: Token,
  tokens: Token[],
  document: TextDocument,
  functionSourceLocation: { start: number; end: number }
) {
  const openBodyParen = tokens.find(
    (t) => t.type === "Punctuator" && t.value === "{"
  );

  if (!functionToken?.range || !openBodyParen?.range) {
    return true;
  }

  const fnLine = document.positionAt(
    functionSourceLocation.start + functionToken.range[0] + 1
  ).line;

  const openBodyParenLine = document.positionAt(
    functionSourceLocation.start + openBodyParen.range[0] + 1
  ).line;

  if (fnLine === openBodyParenLine) {
    return true;
  }

  const keywordLines = tokens
    .filter(isHeaderKeyword)
    .map((t) => t.range)
    .filter((r): r is [number, number] => r !== undefined)
    .map((r) => findLineGivenRange(document, functionSourceLocation, r));

  const allKeywordsOnSameLineAsFn = keywordLines
    .map((l) => l === fnLine)
    .reduce((acc, l) => acc && l, true);

  return allKeywordsOnSameLineAsFn;
}

public async start() {
  process.on("message", async (msg: any) => {
    try {
      await this._handleMessage(msg);
    } catch (error: any) {
      const errorData = error instanceof Error ? error.message : error;

      if (msg.requestId) {
        await this.send(new ErrorResponseMessage(msg.requestId, errorData));
      }
    }
  });

  process.on("disconnect", () => {
    process.exit(0);
  });

  try {
    this._loadHRE();
  } catch (err: any) {
    this.logger.info(`Error loading HRE: ${err}`);
    let errorMessage;
    if (err.message.includes("Cannot find module 'hardhat'")) {
      errorMessage =
        "Couldn't find local hardhat module. Make sure project dependencies are installed.";
    } else {
      errorMessage = err.message;
    }
    await this.send(new InitializationFailureMessage(errorMessage));
    process.exit(1);
  }

  await this.send({ type: MessageType.INITIALIZED });
}

function buildFunctionCompletion(
  node: FunctionDefinition,
  range: { start: VSCodePosition; end: VSCodePosition },
  style: NatspecStyle
) {
  const isMultiLine = style === NatspecStyle.MULTI_LINE;
  const prefix = isMultiLine ? " *" : "///";
  const linesToAdd = [];

  // Include @notice only on public or external functions

  linesToAdd.push(`$0`);

  let tabIndex = 1;
  for (const param of node.parameters) {
    linesToAdd.push(`@param ${param.name} $\{${tabIndex++}}`);
  }

  if ((node.returnParameters ?? []).length >= 2) {
    for (const param of node.returnParameters ?? []) {
      linesToAdd.push(
        `@return ${
          typeof param.name === "string" ? `${param.name} ` : ""
        }$\{${tabIndex++}}`
      );
    }
  }

  let text = isMultiLine ? "\n" : "";

  text += linesToAdd
    .map((line, index) =>
      index !== 0 || isMultiLine ? `${prefix} ${line}` : ` ${line}`
    )
    .join("\n");

  if (isMultiLine) {
    text += "\n";
  }

  return {
    label: "NatSpec function documentation",
    textEdit: {
      range,
      newText: text,
    },
    insertTextFormat: InsertTextFormat.Snippet,
  };
}

async function verifyArtifactsVersion(
  deploymentDir: string | undefined,
): Promise<void> {
  const artifactsDir = `${deploymentDir}/artifacts`;

  if (deploymentDir === undefined || !(await exists(artifactsDir))) {
    return;
  }

  for (const filename of await readdir(artifactsDir)) {
    if (filename.endsWith(".dbg.json")) {
      continue;
    }

    const artifactPath = path.join(artifactsDir, filename);
    const artifact: Artifact = await readJsonFile(artifactPath);

    if (artifact._format === "hh-sol-artifact-1") {
      throw new HardhatError(
        HardhatError.ERRORS.IGNITION.GENERAL.ARTIFACT_MIGRATION_NEEDED,
        {
          deploymentId: deploymentDir.split(path.sep).pop(),
        },
      );
    }
  }

  const buildInfoDir = `${deploymentDir}/build-info`;

  if (!(await exists(buildInfoDir))) {
    return;
  }

  for (const filename of await readdir(buildInfoDir)) {
    const buildInfoPath = path.join(buildInfoDir, filename);
    const buildInfo: BuildInfo = await readJsonFile(buildInfoPath);

    if (buildInfo._format === "hh-sol-build-info-1") {
      throw new HardhatError(
        HardhatError.ERRORS.IGNITION.GENERAL.ARTIFACT_MIGRATION_NEEDED,
        {
          deploymentId: deploymentDir.split(path.sep).pop(),
        },
      );
    }
  }
}
